-- ملء محتوى عنقود "المذاهب الفقهية والفقه المقارن" (madhahib-fiqh-muqaran) —
-- أربعة تصنيفات فرعية، كلها draft (استنفاد كامل للعنقود): التعريف
-- بالمذاهب الأربعة، أسباب اختلاف الفقهاء، أدب الخلاف، منهجية دراسة الفقه
-- المقارن.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس wilaya-islamiyya/usul-fiqh (تعريفي
-- موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الفقه على المذاهب الأربعة لعبد الرحمن الجزيري
-- (التعريف بالمذاهب)، أسباب اختلاف الفقهاء لعلي الخفيف (أسباب الاختلاف)،
-- أدب الخلاف في الإسلام لطه جابر العلواني (أدب الخلاف)، بداية المجتهد
-- ونهاية المقتصد لابن رشد الحفيد (منهجية الفقه المقارن — النموذج
-- الكلاسيكي الأشهر لهذا المنهج).
-- حديثان استُشهد بهما، تحقَّقا حرفياً عبر WebSearch قبل الإدراج (كلاهما
-- صحيح): "إذا حكم الحاكم فاجتهد ثم أصاب فله أجران..." (متفق عليه،
-- البخاري 7352 ومسلم 1716)، وحديث صلاة العصر في بني قريظة (رواه
-- البخاري، عن ابن عمر).
-- آيتان تحقَّقتا حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: النحل 43، النساء 83.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) التعريف بالمذاهب الفقهية الأربعة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e618a0e4-9c2f-4d9b-a937-a93f5affb7a1' AND title='التعريف بالمذاهب الفقهية الأربعة المتبوعة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعريف بالمذاهب الفقهية الأربعة المتبوعة', 'تعريف موجز بالمذاهب الفقهية الأربعة المتبوعة: الحنفي والمالكي والشافعي والحنبلي، أئمتها وانتشارها', 'e618a0e4-9c2f-4d9b-a937-a93f5affb7a1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'المذاهب الأربعة: أئمتها وأصولها وانتشارها', 'المذاهب الفقهية الأربعة المتبوعة عند أهل السنة والجماعة هي طرائق منهجية متكاملة في استنباط الأحكام الشرعية من أدلتها، نشأت واستقرت عبر أئمة بلغوا مرتبة الاجتهاد المطلق، وتبعهم تلاميذهم وأتباعهم من بعدهم فدوّنوا أصولهم وفروعهم. المذهب الحنفي: أسسه الإمام أبو حنيفة النعمان بن ثابت (ت 150هـ) في الكوفة، واشتهر بكثرة الاعتماد على القياس والاستحسان، وهو أوسع المذاهب انتشارًا جغرافيًا اليوم (تركيا وشبه القارة الهندية وآسيا الوسطى). المذهب المالكي: أسسه الإمام مالك بن أنس (ت 179هـ) في المدينة المنورة، واشتهر بالاعتماد على عمل أهل المدينة كدليل إضافي إلى جانب الكتاب والسنة، وينتشر اليوم في المغرب العربي وغرب أفريقيا. المذهب الشافعي: أسسه الإمام محمد بن إدريس الشافعي (ت 204هـ)، وهو أول من دوّن علم أصول الفقه تدوينًا مستقلًا في كتابه "الرسالة"، وينتشر في مصر والشام وشرق أفريقيا وجنوب شرق آسيا. المذهب الحنبلي: أسسه الإمام أحمد بن حنبل (ت 241هـ)، واشتهر بتقديم الحديث الضعيف على القياس في بعض المسائل تحريًا للأثر، وينتشر اليوم في الجزيرة العربية. وهذه المذاهب الأربعة متفقة في أصول الاعتقاد وقطعيات الشريعة، وإنما يقع اختلافها في الفروع الاجتهادية التي يسع فيها الخلاف.', 1),
    (v_lesson, 'examples', 'أصل اتباع أهل العلم من القرآن', 'قال تعالى: ﴿وَمَا أَرْسَلْنَا مِنْ قَبْلِكَ إِلَّا رِجَالًا نُوحِي إِلَيْهِمْ ۚ فَاسْأَلُوا أَهْلَ الذِّكْرِ إِنْ كُنْتُمْ لَا تَعْلَمُونَ﴾ (النحل: 43)، وهي الأصل القرآني في وجوب رجوع من لا يملك أداة الاجتهاد إلى أهل العلم المتخصصين فيما لا يعلمه، وعليها استند العلماء في مشروعية اتباع المقلِّد لمذهب فقهي معتبر من مذاهب أئمة الاجتهاد المتبوعين حين يعجز عن الاجتهاد المباشر في الأدلة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه على المذاهب الأربعة — عبد الرحمن الجزيري', 1);
  END IF;

  -- 2) أسباب اختلاف الفقهاء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9b5fea92-eef1-49b0-a2d4-5df2707bde03' AND title='أسباب اختلاف الفقهاء في الفروع الاجتهادية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أسباب اختلاف الفقهاء في الفروع الاجتهادية', 'تعريف موجز بأبرز أسباب اختلاف الفقهاء فيما يسع فيه الخلاف من المسائل الفقهية', '9b5fea92-eef1-49b0-a2d4-5df2707bde03', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأسباب العلمية لاختلاف الفقهاء', 'اختلاف الفقهاء في الفروع الاجتهادية اختلاف تنوّع لا اختلاف تضاد، وله أسباب علمية منضبطة أحصاها العلماء، من أبرزها: أولاً، اختلاف وصول الأحاديث النبوية إلى الأئمة، إذ لم يكن كل حديث صحيح قد بلغ كل إمام، فقد يفتي إمام بحكم اجتهادًا لعدم بلوغه الحديث الوارد فيه، بينما يأخذ به إمام آخر بلغه. ثانيًا، اختلاف مناهج التصحيح والتضعيف للأحاديث، فقد يصح حديث عند إمام بشروطه في الرواة والاتصال ولا يصح عند آخر لاختلاف شرطهما. ثالثًا، اختلاف دلالات الألفاظ العربية في النصوص، كالاشتراك اللفظي والحقيقة والمجاز والعموم والخصوص، مما يفتح مجال الاجتهاد في فهم النص الواحد. رابعًا، اختلاف الأدلة الاجتهادية المكمّلة كالقياس والاستحسان والمصالح المرسلة وسدّ الذرائع وعمل أهل المدينة، فبعض الأئمة يعتمد دليلًا لا يعتمده غيره أو يقدّمه على غيره عند التعارض. خامسًا، المسائل التي لا نص فيها أصلًا فيجتهد فيها كل إمام برأيه معتمدًا على القواعد العامة للشريعة ومقاصدها. وهذا الاختلاف رحمة بالأمة لا انقسام فيها، ما دام كل مجتهد قد بذل وسعه طلبًا للحق.', 1),
    (v_lesson, 'examples', 'أجر المجتهد المصيب والمخطئ', 'قال النبي صلى الله عليه وسلم: «إذا حكم الحاكم فاجتهد ثم أصاب فله أجران، وإذا حكم فاجتهد ثم أخطأ فله أجر» (رواه البخاري 7352 ومسلم 1716 عن عمرو بن العاص)، وهو الأصل النبوي الذي بُني عليه عذر المجتهدين المختلفين جميعًا، إذ يثبت لكل منهم أجر الاجتهاد ولو أخطأ اجتهاده الحق، فضلاً عمن أصاب فله أجران.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أسباب اختلاف الفقهاء — علي الخفيف', 1);
  END IF;

  -- 3) أدب الخلاف الفقهي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a429747a-c9c8-4d08-9f86-692d5eafd4ff' AND title='أدب الخلاف الفقهي بين الأئمة والمقلِّدين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أدب الخلاف الفقهي بين الأئمة والمقلِّدين', 'تعريف موجز بآداب الخلاف الفقهي وضوابط التعامل مع اختلاف المذاهب المعتبرة', 'a429747a-c9c8-4d08-9f86-692d5eafd4ff', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ضوابط أدب الخلاف الفقهي', 'الخلاف الفقهي فيما يسع فيه الاجتهاد له آداب شرعية ضبطها العلماء صيانةً لوحدة الأمة من أن يتحول الخلاف العلمي إلى تنازع وتفرق. من أبرز هذه الآداب: أولاً، التفريق بين مسائل الاعتقاد القطعية التي لا يسع فيها الخلاف، وبين الفروع الاجتهادية التي يعذر فيها المخالف. ثانيًا، احترام المخالف في الرأي ما دام مستندًا إلى دليل معتبر واجتهاد سائغ، وعدم تبديعه أو تفسيقه بسبب اختلاف اجتهادي. ثالثًا، اجتناب التعصب المذهبي الأعمى الذي يقدّم قول الإمام على الدليل الراجح إذا ظهر، فالمقصود اتباع الحق لا مجرد الانتساب. رابعًا، طلب الحق بالدليل لا المكابرة والانتصار للنفس، فغاية المناظرة الفقهية بلوغ الصواب لا الغلبة. خامسًا، عدم إنكار المسائل الخلافية بالقوة على من عمل بقول آخر معتبر فيها، بل يقتصر الإنكار على ما أجمع عليه العلماء. سادسًا، الجمع بين الثبات على الحق الذي ترجّح للمرء وبين سعة الصدر تجاه من اجتهد فأخطأ، فإن الاختلاف في الفروع لم يمنع الصحابة والتابعين من التآلف والتعاون رغم تعدد اجتهاداتهم.', 1),
    (v_lesson, 'examples', 'قبول النبي صلى الله عليه وسلم لاجتهادين متعارضين', 'عن ابن عمر رضي الله عنهما قال: قال النبي صلى الله عليه وسلم لنا لما رجع من الأحزاب: «لا يصلين أحد العصر إلا في بني قريظة»، فأدرك بعضهم العصر في الطريق، فقال بعضهم: لا نصلي حتى نأتيها، وقال بعضهم: بل نصلي، لم يرد منا ذلك، فذُكر ذلك للنبي صلى الله عليه وسلم فلم يعنِّف واحدًا منهم (رواه البخاري)، وهو أصل نبوي صريح في قبول اختلاف الاجتهاد في فهم الأمر الواحد ما دام كل فريق قد بذل وسعه، وأن مثل هذا الخلاف لا يستوجب تعنيف أحد الفريقين ولا تخطئته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أدب الخلاف في الإسلام — طه جابر العلواني', 1);
  END IF;

  -- 4) منهجية دراسة الفقه المقارن
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='cd958980-2e28-4481-9751-c8928ef673d2' AND title='منهجية دراسة الفقه المقارن') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهجية دراسة الفقه المقارن', 'تعريف موجز بمنهج دراسة الفقه المقارن وخطواته العلمية في عرض أقوال المذاهب وأدلتها والترجيح بينها', 'cd958980-2e28-4481-9751-c8928ef673d2', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'خطوات المنهج العلمي في الفقه المقارن', 'الفقه المقارن هو دراسة المسألة الفقهية الواحدة بعرض أقوال المذاهب المعتبرة فيها جميعًا، مع بيان دليل كل قول ومناقشته، وصولًا إلى ترجيح ما يظهر رجحان دليله، لا مجرد جمع الأقوال دون نظر في أدلتها. وتقوم منهجيته العلمية على خطوات متسلسلة: أولاً، تحرير محل النزاع، أي تحديد موضع الخلاف بدقة وتمييزه عما هو متفق عليه بين المذاهب. ثانيًا، جمع أقوال المذاهب المعتبرة في المسألة من مصادرها المعتمدة لا من كتب أخرى ناقلة قد تنسب لهم غير الصحيح. ثالثًا، ذكر دليل كل قول كما ذكره أصحابه أنفسهم لا كما يتصوره الباحث. رابعًا، مناقشة الأدلة مناقشة علمية موضوعية ببيان وجه الاستدلال وما يرد عليه من اعتراض وما يجاب به عنه. خامسًا، الترجيح بين الأقوال بناءً على قوة الدليل لا على كثرة القائلين أو التعصب المذهبي، مع بيان سبب الترجيح. ولا يصح خوض هذا المنهج قبل إتقان الدارس أصول مذهب واحد إتقانًا جيدًا يؤهله لفهم أدوات الاستدلال والموازنة بين الأقوال، إذ التمكن من فقه مذهب واحد أولًا هو الطريق السليم إلى ممارسة الفقه المقارن بضوابطه العلمية.', 1),
    (v_lesson, 'examples', 'أصل الاستنباط الفقهي من القرآن', 'قال تعالى: ﴿وَإِذَا جَاءَهُمْ أَمْرٌ مِنَ الْأَمْنِ أَوِ الْخَوْفِ أَذَاعُوا بِهِ ۖ وَلَوْ رَدُّوهُ إِلَى الرَّسُولِ وَإِلَىٰ أُولِي الْأَمْرِ مِنْهُمْ لَعَلِمَهُ الَّذِينَ يَسْتَنْبِطُونَهُ مِنْهُمْ﴾ (النساء: 83)، ومنها اشتُق مصطلح "الاستنباط" الذي هو جوهر عمل الفقيه المقارن: استخراج الحكم من دليله بأدوات الاستدلال الصحيحة، وقد نسبت الآية هذا الاستنباط إلى أهل العلم القادرين عليه دون سواهم، وهو الأصل في اشتراط الأهلية العلمية لمن يمارس النظر المقارن بين أقوال المذاهب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بداية المجتهد ونهاية المقتصد — ابن رشد الحفيد', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    'e618a0e4-9c2f-4d9b-a937-a93f5affb7a1', '9b5fea92-eef1-49b0-a2d4-5df2707bde03',
    'a429747a-c9c8-4d08-9f86-692d5eafd4ff', 'cd958980-2e28-4481-9751-c8928ef673d2'
  );
END $$;
